B.YX=s(["Khung th\xf4ng tin khi b\u1ea5m v\xe0o ng\u01b0\u1eddi ch\u01a1i/k\u1ebb \u0111\u1ecbch \u0111\u01b0\u1ee3c l\xe0m l\u1ea1i tr\u1ef1c quan h\u01a1n.","B\u1ed5 sung hi\u1ec3n th\u1ecb c\u1ea5p \u0111\u1ed9 tu luy\u1ec7n (Luy\u1ec7n Kh\xed, Tr\xfac C\u01a1...) trong dialog chi\u1ebfn \u0111\u1ea5u.","B\u1ea3ng k\u1ef9 n\u0103ng v\xe0 tr\u1ea1ng th\xe1i trong tr\u1eadn \u0111\u01b0\u1ee3c c\u1eadp nh\u1eadt s\xe1t v\u1edbi di\u1ec5n bi\u1ebfn hi\u1ec7n t\u1ea1i."],t.s)
B.Go=new A.j0("Chi\u1ebfn \u0111\u1ea5u & giao di\u1ec7n",B.YX)
B.Zs=s(["\u1ee8ng d\u1ee5ng ki\u1ec3m tra phi\xean b\u1ea3n \u0111\u1ecbnh k\u1ef3 \u0111\u1ec3 b\u1ea1n v\u1eabn nh\u1eadn th\xf4ng b\xe1o c\u1eadp nh\u1eadt khi \u0111ang \u1edf m\xe0n kh\xe1c."],t.s)
B.Gm=new A.j0("Th\xf4ng b\xe1o c\u1eadp nh\u1eadt",B.Zs)
