B.Gf=new A.v0("1.0.0.b13","1.0.0.b13 l\xe0m m\u1edbi s\u1ef1 ki\u1ec7n h\u1ed9p qu\xe0 v\xe0 giao di\u1ec7n chi\u1ebfn \u0111\u1ea5u.","B\u1ea3n n\xe0y gi\xfap theo d\xf5i s\u1ef1 ki\u1ec7n r\xf5 r\xe0ng h\u01a1n, nh\u1eadn th\xf4ng b\xe1o ph\u1ea7n th\u01b0\u1edfng tr\u1ef1c ti\u1ebfp v\xe0 hi\u1ec3n th\u1ecb tr\u1ea1ng th\xe1i tr\u1eadn \u0111\u1ea5u tr\u1ef1c quan h\u01a1n.",B.X1)
B.Z5=s(["Ch\u1eb7n m\u1edf PvP Online khi ch\u01b0a c\xf3 nh\xe2n v\u1eadt h\u1ee3p l\u1ec7.","Ch\u1eb7n m\u1edf Shop khi ch\u01b0a c\xf3 nh\xe2n v\u1eadt h\u1ee3p l\u1ec7.","Ch\u1eb7n thao t\xe1c mua v\u1eadt ph\u1ea9m n\u1ebfu m\u1edf Shop tr\u1ef1c ti\u1ebfp m\xe0 ch\u01b0a c\xf3 t\xe0i kho\u1ea3n nh\xe2n v\u1eadt.","Ch\u1eb7n c\xe1c thao t\xe1c c\u1ea7n t\xe0i kho\u1ea3n \u1edf trang ch\u1ee7: sao l\u01b0u, giftcode, \u0111\u1ed5i h\u1ec7, xem k\u1ef9 n\u0103ng, quy \u0111\u1ed5i EXP."],t.s)
B.Gl=new A.j0("T\xe0i kho\u1ea3n & truy c\u1eadp t\xednh n\u0103ng",B.Z5)
B.Zb=s(['Th\u1ed1ng nh\u1ea5t toast: "Y\xeau c\u1ea7u t\xe0i kho\u1ea3n - H\xe3y t\u1ea1o m\u1edbi nh\xe2n v\u1eadt ho\u1eb7c \u0111\u1ed3ng b\u1ed9 t\u1eeb link sao l\u01b0u tr\u01b0\u1edbc."',"Gi\u1ea3m t\xecnh tr\u1ea1ng b\xe1o l\u1ed7i sai ng\u1eef c\u1ea3nh (v\xed d\u1ee5 b\xe1o thi\u1ebfu v\xe0ng khi th\u1ef1c t\u1ebf ch\u01b0a c\xf3 nh\xe2n v\u1eadt)."],t.s)
B.Gj=new A.j0("Th\xf4ng b\xe1o ng\u01b0\u1eddi d\xf9ng",B.Zb)
B.Wl=s([B.Gl,B.Gj],t.sI)
B.Gh=new A.v0("1.0.0.b12","1.0.0.b12 b\u1ed5 sung ch\u1eb7n thao t\xe1c khi ch\u01b0a c\xf3 nh\xe2n v\u1eadt v\xe0 chu\u1ea9n h\xf3a th\xf4ng b\xe1o t\xe0i kho\u1ea3n.","B\u1ea3n n\xe0y kh\xf3a c\xe1c t\xednh n\u0103ng c\u1ea7n t\xe0i kho\u1ea3n khi ng\u01b0\u1eddi ch\u01a1i ch\u01b0a t\u1ea1o nh\xe2n v\u1eadt ho\u1eb7c ch\u01b0a \u0111\u1ed3ng b\u1ed9 d\u1eef li\u1ec7u, \u0111\u1ed3ng th\u1eddi th\u1ed1ng nh\u1ea5t th\xf4ng b\xe1o h\u01b0\u1edbng d\u1eabn thao t\xe1c \u0111\xfang.",B.Wl)
B.Xa=s(["S\u1eeda l\u1ed7i b\xean A \u0111\xe1nh xong nh\u01b0ng b\u1ecb treo cho t\u1edbi khi b\xean B \u0111\xe1nh: nguy\xean nh\xe2n do dedupe seq to\xe0n c\u1ee5c l\xe0m r\u01a1i snapshot h\u1ee3p l\u1ec7.","\u0110\u1ed5i c\u01a1 ch\u1ebf theo d\xf5i seq theo t\u1eebng peer (`fromPeerId + seq`) \u0111\u1ec3 kh\xf4ng drop nh\u1ea7m action/snapshot c\u1ee7a \u0111\u1ed1i th\u1ee7.","G\u1ed9p v\xe0 d\u1ecdn replay sync (`seq=0`) \u0111\u1ec3 tr\xe1nh d\u1ed3n backlog h\xe0ng \u0111\u1ee3i sau nhi\u1ec1u turn.","Gi\u1ea3m th\u1eddi l\u01b0\u1ee3ng animation authoritative (swap/clear/fall) v\xe0 gi\u1edbi h\u1ea1n s\u1ed1 b\u01b0\u1edbc cascade render \u0111\u1ec3 nh\u1ecbp tr\u1eadn \u1ed5n \u0111\u1ecbnh h\u01a1n \u1edf c\xe1c l\u01b0\u1ee3t sau."],t.s)
B.Gk=new A.j0("PvP Online",B.Xa)
B.WM=s(["V\xe1 l\u1ed7i `PlatformException(WebAudioError, Player has not yet been created or has already been disposed)` khi chuy\u1ec3n m\xe0n nhanh.","Chu\u1ea9n h\xf3a lu\u1ed3ng `stop/dispose` c\u1ee7a audio player theo h\u01b0\u1edbng an to\xe0n, kh\xf4ng ph\xe1t sinh unhandled async exception tr\xean Chrome."],t.s)
B.Gp=new A.j0("\xc2m thanh & Web",B.WM)
B.VY=s(["Gi\u1ea3m t\xecnh tr\u1ea1ng kh\xf3a input k\xe9o d\xe0i khi \u0111ang ch\u1edd snapshot cu\u1ed1i c\u1ee7a l\u01b0\u1ee3t v\u1eeba g\u1eedi.","Gi\u1eef t\u01b0\u01a1ng th\xedch v\u1edbi lu\u1ed3ng server authoritative hi\u1ec7n t\u1ea1i, kh\xf4ng thay \u0111\u1ed5i rule gameplay ho\u1eb7c d\u1eef li\u1ec7u k\u1ef9 n\u0103ng."],t.s)
